const req = $input.first().json;
const body = req.body ?? req;
const headers = req.headers ?? {};

// Cloudflare sets CF-Connecting-IP to the real client IP, overwriting any spoofed header
const rawIp = headers['cf-connecting-ip']
  ?? headers['x-forwarded-for']?.split(',')[0]?.trim()
  ?? '';
// Allow only characters valid in IPv4/IPv6 to prevent injection
const ip = /^[0-9a-fA-F:.\[\]]+$/.test(rawIp) ? rawIp : 'unknown';

// Browsers automatically set Origin on cross-origin POST requests
const origin = (headers['origin'] ?? headers['referer'] ?? '').trim();

const slug = (body.client_slug ?? '').toString().trim().toLowerCase();
const message = (body.message ?? '').toString().trim();
let session_id = (body.session_id ?? '').toString().trim();

const errors = [];

if (!slug || !/^[a-z0-9-]{3,50}$/.test(slug)) {
  errors.push('client_slug must be 3-50 lowercase alphanumeric characters or hyphens');
}
if (!message) {
  errors.push('message is required');
} else if (message.length > 2000) {
  errors.push('message must be 2000 characters or fewer');
}
if (!session_id) {
  session_id = 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
    const r = Math.random() * 16 | 0;
    return (c === 'x' ? r : (r & 0x3 | 0x8)).toString(16);
  });
} else if (!/^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(session_id)) {
  errors.push('session_id must be a valid UUID');
}

if (errors.length > 0) {
  return [{ json: { valid: false, error: errors.join('; ') } }];
}

return [{ json: { valid: true, client_slug: slug, message, session_id, ip, origin } }];

const validated = $('Validate Input').first().json;
const rows = $input.all();

if (rows.length === 0) {
  return [{ json: { granted: false, client_id: null, slug: null, reason: 'Client not found', ip: validated.ip, monthly_limit: 500 } }];
}

const row = rows[0].json;
const config = row.config ?? {};
const publicChatConfig = config.public_chat ?? {};
const allowedOrigins = publicChatConfig.allowed_origins ?? [];
const monthlyLimit = Number(publicChatConfig.monthly_limit ?? 500);

// Origin allowlist — enforced only when origins are configured.
// Empty list = open (dev/testing). Browsers always send Origin on cross-origin POST.
if (allowedOrigins.length > 0) {
  let requestHostname = '';
  if (validated.origin) {
    try {
      const url = new URL(validated.origin.includes('://') ? validated.origin : 'https://' + validated.origin);
      requestHostname = url.hostname.toLowerCase();
    } catch (e) { /* unparseable — block */ }
  }
  const originAllowed = allowedOrigins.some(ao => {
    const domain = ao.toLowerCase().replace(/^https?:\/\//, '').replace(/\/.*$/, '');
    return requestHostname === domain || requestHostname.endsWith('.' + domain);
  });
  if (!originAllowed) {
    return [{ json: { granted: false, client_id: row.client_id, slug: row.slug, reason: 'Origin not permitted', ip: validated.ip, monthly_limit: monthlyLimit } }];
  }
}

const granted = !!row.client_id && row.active === true && row.public_chat_enabled === true;
const reason = !row.client_id ? 'Client not found'
  : !row.active ? 'Client account is inactive'
  : !row.public_chat_enabled ? 'Public chat is not enabled for this client'
  : null;

return [{ json: { granted, client_id: row.client_id, slug: row.slug, reason, ip: validated.ip, monthly_limit: monthlyLimit } }];

const counts = $input.first().json;
const access = $('Check Access').first().json;
const monthlyLimit = access.monthly_limit ?? 500;

// 20 completed chats per session per hour
if (Number(counts.session_count) >= 20) {
  return [{ json: { allowed: false, reason: 'Session message limit reached. Please wait before sending more messages.' } }];
}

// 60 gateway requests per IP per hour.
// Skipped when IP is unknown (local dev / non-Cloudflare path).
const skipIpCheck = !access.ip || access.ip === 'unknown';
if (!skipIpCheck && Number(counts.ip_hour_count) >= 60) {
  return [{ json: { allowed: false, reason: 'Too many requests from your network. Please try again later.' } }];
}

// 10 gateway requests per client per minute (concurrency proxy — limits shared resource pressure)
if (Number(counts.client_minute_count) >= 10) {
  return [{ json: { allowed: false, reason: 'The service is currently busy. Please try again in a moment.' } }];
}

// Monthly cap on completed chats (cost control, configurable per client)
if (Number(counts.client_month_count) >= monthlyLimit) {
  return [{ json: { allowed: false, reason: 'Monthly message limit reached for this service.' } }];
}

return [{ json: { allowed: true, reason: null } }];

const validated = $('Validate Input').first().json;
const access = $('Check Access').first().json;
return [{
  json: {
    slug: access.slug,
    message: validated.message,
    session_id: validated.session_id,
    user_id: null,
    role: 'public',
    features: {},
    quick_action_key: null,
    allowed_roles: ['public'],
  }
}];
